// instrStep0SizeCheck is the shared Step 0 size-check + decomposition recipe.
// Both variants emit it verbatim; per-variant preamble runs before it.
const instrStep0SizeCheck = `

## Step 0: size check

The bead is too big when any of these holds:

- More than ~6 ACs spanning unrelated subsystems.
- AC mixes design, implementation, integration tests, and docs as separate top-level deliverables.
- Description names multiple feature-sized sub-pieces.
- More than ~500 lines across more than ~5 files in unrelated packages.
- If the bead description exceeds 8000 bytes, treat Step 0 as a split-first pass and favor child-bead scoping before implementation.
- Auto-decomposition is capped at depth 2: root beads may split once, decomposed children may split once more, and third-level splits must be rejected with an explanation.

If too big, decompose — do not attempt the work:

1. ` + "`ddx bead create`" + ` for each child slice (focused title, description, AC; copy parent's labels and spec-id).
2. ` + "`ddx bead dep add <child-id> <parent-id>`" + ` to record edges.
3. ` + "`ddx bead update <parent-id> --notes 'decomposed into <child-ids>'`" + ` so the decomposition is visible.
4. Write ` + "`{{.AttemptDir}}/no_changes_rationale.txt`" + ` listing each child ID and slice, then stop.

A clean decomposition is a successful attempt. Do not mix partial implementation with decomposition.`

// instrNoChangesContract is the shared NoChangesContract (TD-031 §8.1) rule.
const instrNoChangesContract = `


---

## no_changes contract

If you write ` + "`{{.AttemptDir}}/no_changes_rationale.txt`" + `, it MUST carry one of:

- ` + "`verification_command: <one-line shell command>`" + ` — the loop runs it (cwd = project root, 60s); exit 0 closes the bead, non-zero rejects.
- ` + "`status: needs_investigation`" + ` + ` + "`reason: <why>`" + ` — bead stays open for triage.

Bare rationales ("nothing to do") are rejected.`

// instrInvestigationReports is the shared report-output rule.
const instrInvestigationReports = `

## Reports

Freestanding artifacts (investigation reports, findings docs) go under ` + "`{{.AttemptDir}}/`" + ` (the per-attempt evidence directory under ` + "`.ddx/executions/`" + `). **Never write reports to ` + "`/tmp`" + ` or any path outside the repository** — out-of-repo paths are invisible to the post-merge reviewer and cause BLOCK on missing evidence. If the bead names a specific in-repo path, use it; else default to ` + "`{{.AttemptDir}}/<short-name>.md`" + `. Stage and commit the report alongside code.`

// instrReviewGate is the shared review-as-gate rule.
const instrReviewGate = `

## Review gate

- The review is a gate, not an escape hatch — meet every AC in this pass.
- Address every BLOCKING ` + "`<review-findings>`" + ` item; do not declare ` + "`no_changes`" + ` with blocking findings open.`

// instrBeadOverride is the shared bead-overrides-defaults rule.
const instrBeadOverride = `

## Bead overrides project defaults

The bead description and AC override CLAUDE.md, AGENTS.md, and conservative project defaults (YAGNI, DOWITYTD, no-docs-unless-asked) in this worktree — write whatever the bead asks for.`

// instrCoreConstraints is the shared core-constraints tail.
const instrCoreConstraints = `

## Constraints

- Work only inside this execution worktree.
- Keep ` + "`.ddx/executions/`" + ` intact — DDx uses it as execution evidence.
- **Never run ` + "`ddx init`" + `** — the workspace is initialized; running it corrupts the bead queue.
- Do not modify files outside the bead's named scope.
- Do not rewrite CLAUDE.md, AGENTS.md, or other project-instructions files unless the bead asks.`

// executeBeadInstructionsClaudeText is the <instructions> body used when the
// harness carries its own rich system prompt (claude, codex, opencode,
// unknown). It composes a Claude-specific preamble + process body with the
// shared instr* blocks.
const executeBeadInstructionsClaudeText = `You are executing one bead inside an isolated DDx execution worktree. The bead's <description> and <acceptance> are the completion contract — every AC must be provably satisfied by a specific code, test, or file you can point to after your commit.` +
	instrStep0SizeCheck +
	`

## How to work

- Read first. If the bead names files, specs, or prior beads, read them before editing — do not guess.
- Cross-reference each AC against concrete evidence (test name, file path, function) before committing. If you cannot point at it, it is not done.
- Run the project's test and lint commands before committing. **Do not commit red code** — fix failures first.
- Stage with ` + "`git add <specific-paths>`" + `; never ` + "`git add -A`" + ` (the worktree may have unrelated WIP).
- Commit exactly once when green; conventional-commit subject ending with ` + "`[<bead-id>]`" + `. Stop after the commit.
- Do not modify files outside the bead's scope.
- If you cannot finish, write ` + "`{{.AttemptDir}}/no_changes_rationale.txt`" + ` (what is done, what blocks, what a follow-up needs) before exiting. No commit and no rationale ⇒ DDx records ` + "`no_evidence_produced`" + `. A well-justified no_changes beats a bad commit.` +
	instrNoChangesContract +
	instrInvestigationReports +
	instrBeadOverride +
	instrReviewGate +
	instrCoreConstraints +
	`

## When the work is done

After the commit succeeds and every AC is verified, stop. Return control to the orchestrator — do not keep exploring or testing.`

// executeBeadInstructionsAgentText is the <instructions> body used when the
// harness selector routes to the embedded Fizeau agent (agent / fiz /
// embedded). It composes an agent-specific preamble + tool-aware process
// body with the shared instr* blocks. The Agent variant carries the
// stop-after-commit runaway guard (codex catch).
const executeBeadInstructionsAgentText = `You are a coding agent executing one bead inside an isolated DDx execution worktree. Tools: read, write, edit, bash, ls, grep, find. Use them — do not shell out to ` + "`bash: cat`" + `, ` + "`bash: rg`" + `, or ` + "`bash: ls`" + `.

The bead's <description> and <acceptance> are the completion contract. Every AC must be satisfied by code you write in this pass.` +
	instrStep0SizeCheck +
	`

## Process

- Read first. Read the files the bead names before editing — do not guess.
- Use ` + "`edit`" + ` for changes to existing files; ` + "`write`" + ` for new files; ` + "`read`" + ` / ` + "`grep`" + ` / ` + "`ls`" + ` for inspection (never the bash equivalents).
- Run the project's test and lint commands before committing. **Do not commit red code** — diagnose and fix.
- Stage with ` + "`git add <specific-paths>`" + `; never ` + "`git add -A`" + `.
- Commit exactly once when green; conventional-commit subject ending with ` + "`[<bead-id>]`" + `. Implementation and tests in the same commit.
- Stop immediately after the commit succeeds. Do not keep reading, testing, or following up — that risks runaway loops.
- Do not modify files outside the bead's scope.

package agent

import (
	"context"
	"path/filepath"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// newCancelTestBeadStore returns a real *bead.Store rooted at projectRoot/.ddx,
// with one open bead pre-created so the worker's poll path has a real backing
// document to read. setupArtifactTestProjectRoot already created the .ddx
// directory; the worker's prepareArtifacts populates a bead inside the
// per-attempt worktree, but the cancel poll reads from projectRoot's store.
func newCancelTestBeadStore(t *testing.T, projectRoot, beadID string) *bead.Store {
	t.Helper()
	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
	if err := store.Init(); err != nil {
		t.Fatal(err)
	}
	if err := store.Create(&bead.Bead{ID: beadID, Title: "cancel integration bead", Status: bead.StatusInProgress}); err != nil {
		t.Fatal(err)
	}
	return store
}

// fakeCancelStore is a memory-only BeadCancelStore for worker tests. The
// trigger channel pings the poll loop the moment the test wants the marker
// observed (instead of waiting for the next CancelPollInterval tick to fire
// against a real bead store on disk).
type fakeCancelStore struct {
	mu        sync.Mutex
	requested bool
	honored   bool
	calls     atomic.Int32
}

func (f *fakeCancelStore) IsCancelRequested(id string) (bool, error) {
	f.calls.Add(1)
	f.mu.Lock()
	defer f.mu.Unlock()
	if f.honored {
		return false, nil
	}
	return f.requested, nil
}

func (f *fakeCancelStore) MarkCancelHonored(id string) error {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.honored = true
	return nil
}

func (f *fakeCancelStore) request() {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.requested = true
}

func (f *fakeCancelStore) wasHonored() bool {
	f.mu.Lock()
	defer f.mu.Unlock()
	return f.honored
}

// blockingAgentRunner blocks Run until ctx cancels, then returns a non-zero
// exit code (mirroring what a real subprocess does when its context dies).
// startedAt is closed once Run is on the blocking select so tests can
// deterministically race their cancel write against the in-flight attempt.
type blockingAgentRunner struct {
	startedAt chan struct{}
	once      sync.Once
}

func (r *blockingAgentRunner) Run(opts RunArgs) (*Result, error) {
	r.once.Do(func() { close(r.startedAt) })
	ctx := opts.Context
	if ctx == nil {
		ctx = context.Background()
	}
	<-ctx.Done()
	return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
}

func newBlockingAgentRunner() *blockingAgentRunner {
	return &blockingAgentRunner{startedAt: make(chan struct{})}
}

// TestWorker_HonorsCancelMidAttempt: when the operator-cancel marker flips
// while an attempt is mid-flight, the worker cancels the dispatch context,
// marks cancel-honored, and emits a preserved_for_review result with reason
// operator_cancel. ADR-022 §Cancel SLA, AC#3.
func TestWorker_HonorsCancelMidAttempt(t *testing.T) {
	const beadID = "ddx-cancel-mid"

	prev := CancelPollInterval
	CancelPollInterval = 25 * time.Millisecond
	t.Cleanup(func() { CancelPollInterval = prev })

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "cancel0000000001",
		resultRev:   "cancel0000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	cancelStore := &fakeCancelStore{}
	runner := newBlockingAgentRunner()

	// Flip the cancel marker as soon as the runner is in its blocking select.
	go func() {
		<-runner.startedAt
		cancelStore.request()
	}()

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	done := make(chan *ExecuteBeadResult, 1)
	go func() {
		res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
			BeadCancel:  cancelStore,
		}, gitOps)
		if err != nil {
			t.Errorf("ExecuteBeadWithConfig: %v", err)
		}
		done <- res
	}()

	var res *ExecuteBeadResult
	select {
	case res = <-done:
	case <-time.After(5 * time.Second):
		t.Fatal("worker did not return within 5s after cancel; mid-attempt poll did not abort")
	}

	if res == nil {
		t.Fatal("nil result")
	}
	if res.Outcome != "preserved" {
		t.Errorf("Outcome = %q, want %q", res.Outcome, "preserved")
	}
	if res.Reason != OperatorCancelReason {
		t.Errorf("Reason = %q, want %q", res.Reason, OperatorCancelReason)
	}
	if res.Status != ExecuteBeadStatusPreservedNeedsReview {
		t.Errorf("Status = %q, want %q", res.Status, ExecuteBeadStatusPreservedNeedsReview)
	}
	if !cancelStore.wasHonored() {
		t.Error("cancel-honored was not set on the cancel store")
	}
}

// TestCancelLatency_UnderSLA: the worker observes cancel and returns within
// a small multiple of CancelPollInterval (the SLA contract — ADR-022 §Cancel
// SLA promises observation within one poll interval at the next safe point).
func TestCancelLatency_UnderSLA(t *testing.T) {
	const beadID = "ddx-cancel-sla"
	const pollInterval = 50 * time.Millisecond

	prev := CancelPollInterval
	CancelPollInterval = pollInterval
	t.Cleanup(func() { CancelPollInterval = prev })

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "sla0000000000001",
		resultRev:   "sla0000000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	cancelStore := &fakeCancelStore{}
	runner := newBlockingAgentRunner()

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	startedDispatch := make(chan struct{})
	done := make(chan *ExecuteBeadResult, 1)
	go func() {
		close(startedDispatch)
		res, _ := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
			BeadCancel:  cancelStore,
		}, gitOps)
		done <- res
	}()

	<-startedDispatch
	<-runner.startedAt
	cancelStore.request()
	cancelAt := time.Now()

	select {
	case res := <-done:
		latency := time.Since(cancelAt)
		// Allow up to 4× the poll interval to absorb scheduler + worktree
		// teardown overhead. The SLA contract is "within one poll interval at
		// the next safe point"; this test asserts the bound is honored, not
		// the wall-clock minimum.
		if latency > 4*pollInterval+250*time.Millisecond {
			t.Errorf("cancel latency %v exceeded SLA budget (%v)", latency, 4*pollInterval+250*time.Millisecond)
		}
		if res == nil || res.Reason != OperatorCancelReason {
			t.Errorf("expected operator_cancel result, got %+v", res)
		}
	case <-time.After(5 * time.Second):
		t.Fatal("cancel did not propagate within 5s")
	}
}

// TestOperatorCancel_DuringRealClaudeAttempt is the WIRED-IN integration test
// (AC#7). Instead of swapping in a stub for dispatchAgentRun, it exercises
// the real end-to-end path: a long-running script-style runner that polls the
// caller's context (the same contract a real claude subprocess satisfies via
// SIGTERM on cancel) is dispatched by ExecuteBeadWithConfig; the operator
// cancel marker is flipped on a real *bead.Store via RequestCancel; the
// worker must observe the marker through its mid-attempt poll, propagate
// cancellation into the in-flight dispatch (proving the subprocess receives
// the cancel signal), and emit preserved_for_review/operator_cancel.
//
// This is not a stub-attempt cancel — RequestCancel writes to the same bead
// store the worker reads, and the runner only returns when its dispatch ctx
// is cancelled by the poll loop, demonstrating the cancel actually traveled
// through the live signal path.
func TestOperatorCancel_DuringRealClaudeAttempt(t *testing.T) {
	const beadID = "ddx-cancel-realattempt"

	prev := CancelPollInterval
	CancelPollInterval = 25 * time.Millisecond
	t.Cleanup(func() { CancelPollInterval = prev })

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "real000000000001",
		resultRev:   "real000000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	// Use the real *bead.Store rooted at the project's .ddx, the same one
	// the server's handleCancelBead writes to via beadStoreForRequest.
	beadStore := newCancelTestBeadStore(t, projectRoot, beadID)

	// A runner that blocks like a real claude subprocess until its context
	// is signalled. Exit code 1 + ctx.Err() mirrors what the OS executor
	// returns when SIGTERM kills the child mid-stream.

---
	// returns when SIGTERM kills the child mid-stream.
	runner := newBlockingAgentRunner()

	// The "operator" hits POST /api/beads/<id>/cancel — modeled here by
	// calling RequestCancel directly, the function the HTTP handler calls.
	subprocessSawCancel := make(chan struct{})
	go func() {
		<-runner.startedAt
		// Wait one extra tick to make sure the worker's poll loop is the
		// one that drives the abort, not a context already-cancelled state.
		time.Sleep(2 * CancelPollInterval)
		if _, err := beadStore.RequestCancel(beadID); err != nil {
			t.Errorf("RequestCancel: %v", err)
		}
		close(subprocessSawCancel)
	}()

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	done := make(chan *ExecuteBeadResult, 1)
	go func() {
		res, _ := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
			BeadCancel:  beadStore,
		}, gitOps)
		done <- res
	}()

	<-subprocessSawCancel

	var res *ExecuteBeadResult
	select {
	case res = <-done:
	case <-time.After(10 * time.Second):
		t.Fatal("worker did not honor cancel on a real attempt within 10s")
	}

	if res == nil || res.Reason != OperatorCancelReason {
		t.Fatalf("expected preserved/operator_cancel, got %+v", res)
	}
	if res.Status != ExecuteBeadStatusPreservedNeedsReview {
		t.Errorf("Status = %q, want %q", res.Status, ExecuteBeadStatusPreservedNeedsReview)
	}

	// And the cancel-honored marker must be persisted on the real bead.
	requested, err := beadStore.IsCancelRequested(beadID)
	if err != nil {
		t.Fatalf("IsCancelRequested: %v", err)
	}
	if requested {
		t.Error("IsCancelRequested still true after worker honored — cancel-honored marker missing")
	}
}

package cmd

import (
	"context"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/agent/workerprobe"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	serverpkg "github.com/DocumentDrivenDX/ddx/internal/server"
	"github.com/spf13/cobra"
)

// Exit codes for ddx try terminal outcomes. These are specific to ddx try
// and intentionally do not reuse the generic ExitCode* constants because
// the bead-execution outcome vocabulary is distinct from generic CLI errors.
const (
	tryExitSuccess         = 0 // success or already_satisfied
	tryExitPreservedOrNone = 1 // preserved_for_review or no_changes
	tryExitFailed          = 2 // execution_failed or any other terminal non-success
)

// newTryCommand creates the top-level "ddx try <bead-id>" command.
// It targets a single specific bead through the full production execution
// machinery (claim → execute → land → review), unlike "ddx work" which drains
// the queue by picker priority and cannot force a specific bead.
func (f *CommandFactory) newTryCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:          "try <bead-id>",
		Short:        "Execute a specific bead through the production machinery",
		SilenceUsage: true,
		Long: `try executes a single named bead through the full production
execution machinery: claim → execute → land → review.

Unlike "ddx work" which drains the queue by picker priority, "ddx try"
targets a specific bead ID. This is useful for:
  - Operator-driven debugging when a bead misbehaves under autonomous drain
  - Deterministic queue ordering during refactor execution (dispatch each child
    in dep order with an explicit ID)
  - Path-comparison studies that need to execute one fixture bead at a time

Pre-flight checks (run before any claim is issued):
  - bead not found → non-zero exit with "bead not found: <id>"
  - bead not claimable (status=closed, cancelled, etc.) → non-zero exit
  - bead has unmet dependencies → non-zero exit listing the blockers

Review is on by default. --no-review is a break-glass override and
requires --no-review-i-know-what-im-doing. A bead label of review:skip
is only honored when it also carries a sibling review:skip-reason:*
label; otherwise the label is ignored.

Flag plumbing is identical to "ddx work": --harness, --model, --provider,
--profile, --effort are forwarded to the agent as opaque passthrough
constraints. DDx does not validate or branch on their string values.

Exit codes:
  0  success or already_satisfied
  1  preserved_for_review or no_changes
  2  execution_failed or any other terminal non-success
`,
		Example: `  # Execute a specific bead
  ddx try ddx-abc12345

  # Execute with an explicit harness and model
  ddx try ddx-abc12345 --harness codex --model gpt-5.4-mini

  # Execute without the post-merge review step (break-glass only)
  ddx try ddx-abc12345 --no-review --no-review-i-know-what-im-doing`,
		Args: cobra.ExactArgs(1),
		RunE: f.runTry,
	}

	// Routing knobs — identical to "ddx work" passthrough surface.
	cmd.Flags().String("project", "", "Target project root path or name (default: CWD git root). Env: DDX_PROJECT_ROOT")
	cmd.Flags().String("from", "", "Base git revision to start from (default: HEAD)")
	cmd.Flags().String("harness", "", "Agent harness constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("model", "", "Model constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("profile", agent.DefaultRoutingProfile, "Routing profile: default, cheap, fast, or smart")
	cmd.Flags().String("provider", "", "Provider constraint (passthrough; ddx try does not validate)")
	cmd.Flags().String("model-ref", "", "Model catalog reference (e.g. code-medium); resolved via the model catalog")
	cmd.Flags().String("effort", "", "Effort level")
	cmd.Flags().Bool("no-review", false, "Skip post-merge review (break-glass: requires --no-review-i-know-what-im-doing)")
	cmd.Flags().Bool("no-review-i-know-what-im-doing", false, "Break-glass acknowledgement required when using --no-review")
	cmd.Flags().String("review-harness", "", "Harness for the post-merge reviewer (default: same as implementation harness)")
	cmd.Flags().String("review-model", "", "Model override for the post-merge reviewer (default: smart tier)")
	cmd.Flags().Duration("request-timeout", 0, "Per-request provider wall-clock timeout; overrides project config and model-class defaults")
	cmd.Flags().Int("min-power", 0, "Minimum model power required (0 = unconstrained)")
	cmd.Flags().Int("max-power", 0, "Maximum model power allowed (0 = unconstrained)")

	return cmd
}

// runTry is the RunE for "ddx try <bead-id>".
func (f *CommandFactory) runTry(cmd *cobra.Command, args []string) error {
	beadID := args[0]

	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	fromRev, _ := cmd.Flags().GetString("from")
	harness, _ := cmd.Flags().GetString("harness")
	model, _ := cmd.Flags().GetString("model")
	profile, _ := cmd.Flags().GetString("profile")
	provider, _ := cmd.Flags().GetString("provider")
	modelRef, _ := cmd.Flags().GetString("model-ref")
	effort, _ := cmd.Flags().GetString("effort")
	noReview, _ := cmd.Flags().GetBool("no-review")
	noReviewAck, _ := cmd.Flags().GetBool("no-review-i-know-what-im-doing")
	reviewHarness, _ := cmd.Flags().GetString("review-harness")
	reviewModel, _ := cmd.Flags().GetString("review-model")
	requestTimeout, _ := cmd.Flags().GetDuration("request-timeout")
	minPower, _ := cmd.Flags().GetInt("min-power")
	maxPower, _ := cmd.Flags().GetInt("max-power")

	if noReview && !noReviewAck {
		return fmt.Errorf("--no-review requires --no-review-i-know-what-im-doing (break-glass acknowledgement)")
	}

	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))

	// Pre-flight: look up the bead.
	target, err := store.Get(beadID)
	if err != nil {
		fmt.Fprintf(cmd.ErrOrStderr(), "bead not found: %s\n", beadID)
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	// Pre-flight: verify the bead is in a claimable state.
	// Claimable = open, or stale in_progress (the loop handles stale reclaim).
	switch target.Status {
	case bead.StatusOpen, bead.StatusInProgress:
		// allowed — loop's Claim() handles stale-heartbeat reclaim
	default:
		fmt.Fprintf(cmd.ErrOrStderr(), "bead is not claimable (status=%s)\n", target.Status)
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	// Pre-flight: check for unmet dependencies.
	if unmet := unmetDeps(store, target); len(unmet) > 0 {
		fmt.Fprintf(cmd.ErrOrStderr(), "bead has unmet dependencies: %s\n", strings.Join(unmet, ", "))
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	// Wrap the real store so that ReadyExecution() returns only the target bead.
	// All other operations pass through to the underlying store unchanged.
	forcedStore := &singleBeadStore{Store: store, target: *target}

	// Set up progress logging (same as runAgentExecuteLoopImpl).
	loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
	loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
	_ = os.MkdirAll(loopLogDir, 0o755)
	loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
	var loopSink io.Writer
	if lf, openErr := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); openErr == nil {
		loopSink = lf
		defer lf.Close() //nolint:errcheck
	}

	// Worker-probe (best-effort server mirror; non-blocking).
	probeIdent := workerprobe.Identity{
		ProjectRoot:  projectRoot,
		Harness:      harness,
		Model:        model,
		ExecutorPID:  os.Getpid(),
		ExecutorHost: hostnameOrEmpty(),
		StartedAt:    time.Now().UTC(),
	}
	probe := workerprobe.New(probeIdent, workerprobe.Config{
		AddrFunc: serverpkg.ReadServerAddr,
	})
	probeCtx, probeCancel := context.WithCancel(context.Background())
	probe.Start(probeCtx)
