				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "pre-claim intake: %s (skipping %s)\n", intakeOutcome, candidate.ID)
				}
				emit("pre_claim_intake.blocked", map[string]any{
					"bead_id": candidate.ID,
